import { describe, expect, it } from "vitest";
import { priceOrder } from "../src/pricing.js";

describe("priceOrder", () => {
  describe("subtotal", () => {
    it("returns all zeros for an empty order", () => {
      expect(priceOrder([])).toEqual({
        subtotalCents: 0,
        discountCents: 0,
        totalCents: 0,
      });
    });

    it("sums unitCents * qty for a single line", () => {
      expect(priceOrder([{ unitCents: 5000, qty: 2 }])).toMatchObject({
        subtotalCents: 10000,
      });
    });

    it("sums across multiple lines", () => {
      // 100*3 + 250*2 = 300 + 500 = 800
      expect(priceOrder([
        { unitCents: 100, qty: 3 },
        { unitCents: 250, qty: 2 },
      ])).toEqual({
        subtotalCents: 800,
        discountCents: 0,
        totalCents: 800,
      });
    });
  });

  describe("qty validation", () => {
    it("throws RangeError for qty of 0", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: 0 }])).toThrow(RangeError);
    });

    it("throws RangeError for negative qty", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: -2 }])).toThrow(RangeError);
    });

    it("throws RangeError for a non-integer qty", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: 1.5 }])).toThrow(RangeError);
    });

    it("throws RangeError for a non-numeric qty", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: "2" }])).toThrow(RangeError);
    });

    it("includes the offending qty in the error message", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: 0 }])).toThrow("invalid qty 0");
    });

    it("throws if any line has an invalid qty, even when others are valid", () => {
      expect(() => priceOrder([
        { unitCents: 100, qty: 1 },
        { unitCents: 200, qty: 0 },
      ])).toThrow(RangeError);
    });

    it("accepts a qty of 1", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: 1 }])).not.toThrow();
    });
  });

  describe("tier discount", () => {
    it("applies no tier discount below the 10000 threshold", () => {
      expect(priceOrder([{ unitCents: 9999, qty: 1 }])).toEqual({
        subtotalCents: 9999,
        discountCents: 0,
        totalCents: 9999,
      });
    });

    it("applies 10% at exactly 10000", () => {
      expect(priceOrder([{ unitCents: 10000, qty: 1 }])).toEqual({
        subtotalCents: 10000,
        discountCents: 1000,
        totalCents: 9000,
      });
    });

    it("rounds the tier discount to the nearest cent, .5 rounding up", () => {
      // 10005 * 0.1 = 1000.5 -> 1001
      expect(priceOrder([{ unitCents: 10005, qty: 1 }])).toEqual({
        subtotalCents: 10005,
        discountCents: 1001,
        totalCents: 9004,
      });
    });
  });

  describe("coupon discount", () => {
    it("applies the coupon pct against the subtotal when no tier discount applies", () => {
      // 5000 * 20% = 1000
      expect(priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 20 })).toEqual({
        subtotalCents: 5000,
        discountCents: 1000,
        totalCents: 4000,
      });
    });

    it("applies the coupon against the subtotal AFTER the tier discount", () => {
      // subtotal 10000, tier 1000, afterTier 9000, coupon 10% = 900
      // discount = 1000 + 900 = 1900
      expect(priceOrder([{ unitCents: 10000, qty: 1 }], { pct: 10 })).toEqual({
        subtotalCents: 10000,
        discountCents: 1900,
        totalCents: 8100,
      });
    });

    it("caps pct above 30 at 30", () => {
      // pct 50 behaves as 30: 5000 * 30% = 1500
      expect(priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 50 })).toEqual({
        subtotalCents: 5000,
        discountCents: 1500,
        totalCents: 3500,
      });
    });

    it("caps pct just above the boundary (31 -> 30)", () => {
      // subtotal 10000, tier 1000, afterTier 9000, coupon 30% = 2700
      expect(priceOrder([{ unitCents: 10000, qty: 1 }], { pct: 31 })).toEqual({
        subtotalCents: 10000,
        discountCents: 3700,
        totalCents: 6300,
      });
    });

    it("does not cap pct at exactly 30", () => {
      // 5000 * 30% = 1500 (same result as capped 50 case, verifying 30 is allowed)
      expect(priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 30 })).toEqual({
        subtotalCents: 5000,
        discountCents: 1500,
        totalCents: 3500,
      });
    });

    it("applies a 0% coupon as no discount", () => {
      expect(priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 0 })).toEqual({
        subtotalCents: 5000,
        discountCents: 0,
        totalCents: 5000,
      });
    });

    it("rounds the coupon discount to the nearest cent, .5 rounding up", () => {
      // 4950 * 5% = 247.5 -> 248
      expect(priceOrder([{ unitCents: 4950, qty: 1 }], { pct: 5 })).toEqual({
        subtotalCents: 4950,
        discountCents: 248,
        totalCents: 4702,
      });
    });
  });

  describe("combined tier + coupon", () => {
    it("stacks and independently rounds both discounts", () => {
      // subtotal 12345, tier = round(1234.5) = 1235, afterTier = 11110
      // coupon 15% = round(1666.5) = 1667, discount = 1235 + 1667 = 2902
      expect(priceOrder([{ unitCents: 12345, qty: 1 }], { pct: 15 })).toEqual({
        subtotalCents: 12345,
        discountCents: 2902,
        totalCents: 9443,
      });
    });
  });

  describe("no coupon provided", () => {
    it("applies only the tier discount when coupon is omitted", () => {
      expect(priceOrder([{ unitCents: 2500, qty: 2 }])).toMatchObject({
        subtotalCents: 5000,
        discountCents: 0,
      });
    });
  });
});

